def verify_signature(payload: str, signature: str, secret: str) -> bool:
    """Verify HMAC signature of the payload"""
    if not signature or not secret:
        return False
    
    try:
        expected_signature = hmac.new(
            secret.encode('utf-8'),
            payload.encode('utf-8'),
            hashlib.sha256
        ).hexdigest()
        
        # Remove prefix if present (e.g., "sha256=")
        if '=' in signature:
            signature = signature.split('=')[1]
        
        return hmac.compare_digest(expected_signature, signature)
    except Exception as e:
        logging.error(f"Signature verification error: {str(e)}")
        return False

def check_ip_whitelist(ip_address: str) -> bool:
    """Check if IP is in whitelist"""
    if not ALLOWED_IPS or ALLOWED_IPS == ['']:
        return True  # No IP restriction if not configured
    
    return ip_address in ALLOWED_IPS

def check_rate_limit(identifier: str) -> bool:
    """Simple rate limiting check"""
    current_time = time.time()
    
    if identifier not in request_tracker:
        request_tracker[identifier] = []
    
    # Clean old requests
    request_tracker[identifier] = [
        req_time for req_time in request_tracker[identifier]
        if current_time - req_time < RATE_LIMIT_WINDOW
    ]
    
    # Check limit
    if len(request_tracker[identifier]) >= RATE_LIMIT_MAX_REQUESTS:
        return False
    
    request_tracker[identifier].append(current_time)
    return True

def validate_payload(payload: Dict[str, Any]) -> tuple[bool, Optional[str]]:
    """Validate payload structure and content"""
    required_fields = ['transaction_id', 'amount', 'currency', 'status', 'timestamp']
    
    for field in required_fields:
        if field not in payload:
            return False, f"Missing required field: {field}"
    
    # Validate data types
    if not isinstance(payload.get('amount'), (int, float)):
        return False, "Invalid amount format"
    
    if not isinstance(payload.get('transaction_id'), str):
        return False, "Invalid transaction_id format"
    
    if not isinstance(payload.get('currency'), str) or len(payload['currency']) != 3:
        return False, "Invalid currency format"
    
    allowed_statuses = ['pending', 'completed', 'failed', 'refunded']
    if payload.get('status') not in allowed_statuses:
        return False, f"Invalid status. Must be one of: {allowed_statuses}"
    
    # Validate timestamp (should be recent)
    try:
        timestamp = int(payload['timestamp'])
        current_time = int(time.time())
        time_diff = abs(current_time - timestamp)
        
        # Reject if timestamp is more than 5 minutes old or in future
        if time_diff > 300:
            return False, "Timestamp too old or in future"
    except (ValueError, TypeError):
        return False, "Invalid timestamp format"
    
    return True, None

def sanitize_input(data: Dict[str, Any]) -> Dict[str, Any]:
    """Sanitize input data to prevent injection attacks"""
    sanitized = {}
    
    for key, value in data.items():
        # Limit key length
        if len(str(key)) > 100:
            continue
        
        if isinstance(value, str):
            # Limit string length
            value = value[:1000]
            # Remove potentially dangerous characters
